#!/usr/bin/env python3
"""
SIOP ML Competition — single-file submission entrypoint - WangP

What it does
------------
Runs the full effect-size pipeline in order: two independent LLM runs on each
study, reconciliation when they disagree, then a pass for missing or
suspicious aggregates. Inputs are always taken from *this submission folder*:

  pdfs/                  — one PDF per study (filenames must match study_definitions)
  study_definitions.csv  — per-study research question, construct text, and verbatim definitions

How it is packaged
------------------
The logic lives in several modules (pipeline, conversions, three stage scripts).
For a one-file deliverable, those files are embedded below as zlib-compressed
base64 strings. On first run they are written under the system temp directory and
imported from there; intermediate outputs (reasoning1/, reasoning2/, etc.) are
written next to those extracted files, not necessarily beside this script.

How to run
----------
  python run_submission.py --workers 4 --provider openai \\
      --run1-provider openai --run2-provider openai

Set API keys in the environment or a ``.env`` file (see README). ``--provider``
must match the keys you configure for stages 2-3; ``--run1-provider`` /
``--run2-provider`` configure the two runs in stage 1.
"""

from __future__ import annotations

import argparse
import base64
import importlib
import os
import tempfile
import zlib
import sys
from pathlib import Path


# ---------------------------------------------------------------------------
# Embedded module bundle: zlib-compressed, base64-encoded copies of
# effect_size_conversion, effect_size_pipeline, run_study, reconcile_reasoning,
# and empty_estimate. Regenerate from the repo if those sources change; do not
# hand-edit the payloads. Judges run this single file without the rest of the tree.
# ---------------------------------------------------------------------------
_EMBEDDED_B64_ZLIB: dict[str, str] = {
    "effect_size_conversion.py": "",
    "effect_size_pipeline.py": "",
    "run_study.py": "",
    "reconcile_reasoning.py": "",
    "empty_estimate.py": "",
}


def _materialize_embedded_modules(dest_dir: Path) -> None:
    """Write each embedded module to ``dest_dir`` once (skip non-empty existing files)."""
    dest_dir.mkdir(parents=True, exist_ok=True)
    for filename, b64 in _EMBEDDED_B64_ZLIB.items():
        out_path = dest_dir / filename
        if out_path.exists() and out_path.stat().st_size > 0:
            continue
        raw = zlib.decompress(base64.b64decode(b64.encode("ascii")))
        out_path.write_bytes(raw)


def _prepare_import_path() -> Path:
    """Extract embedded modules to a temp folder and prepend it to ``sys.path``."""
    tmp_root = Path(tempfile.gettempdir()) / "siop_submission_embedded"
    mod_dir = tmp_root / "embedded_modules"
    _materialize_embedded_modules(mod_dir)
    if str(mod_dir) not in sys.path:
        sys.path.insert(0, str(mod_dir))
    return mod_dir


def _patch_dataset_paths_for_submission(submission_dir: Path, *, provider: str) -> None:
    """Point ``effect_size_pipeline`` at this folder's ``pdfs/`` and ``study_definitions.csv``.

    Stage scripts bind ``TEST_PDF_DIR`` and similar names at import time, so we set
    ``LLM_PROVIDER``, load ``effect_size_pipeline``, overwrite its path globals, then
    clear the construct-definition cache before any stage imports those values.
    """
    os.environ["LLM_PROVIDER"] = provider

    _prepare_import_path()
    import effect_size_pipeline as esp  # noqa: F401

    pdf_dir = (submission_dir / "pdfs").resolve()
    defs_csv = (submission_dir / "study_definitions.csv").resolve()

    if not pdf_dir.exists():
        raise FileNotFoundError(f"Missing submission PDFs directory: {pdf_dir}")
    if not defs_csv.exists():
        raise FileNotFoundError(f"Missing submission study_definitions.csv: {defs_csv}")

    esp.ACTIVE_DATASET = "submission"
    esp._ACTIVE_DIR = submission_dir.resolve()
    esp.DEFAULT_PDF_DIR = pdf_dir
    esp.TEST_DATASET_DIR = submission_dir.resolve()
    esp.TEST_PDF_DIR = pdf_dir
    esp.STUDY_DEFINITIONS_CSV = defs_csv

    try:
        esp._pair_definitions_cache.clear()
    except Exception:
        pass


def _run_stage(module_name: str, workers: int, *, extra_args: list[str] | None = None) -> None:
    """Import an embedded stage module and invoke its ``main()`` with a synthetic ``sys.argv``."""
    mod = importlib.import_module(module_name)
    if not hasattr(mod, "main"):
        raise AttributeError(f"{module_name}.py has no main()")

    argv0 = sys.argv[0]
    old_argv = sys.argv[:]
    try:
        sys.argv = [argv0, "--workers", str(workers)]
        if extra_args:
            sys.argv.extend(extra_args)
        mod.main()
    finally:
        sys.argv = old_argv


def main() -> None:
    ap = argparse.ArgumentParser(
        description="Run the three-stage effect-size pipeline on this folder's PDFs and study_definitions.csv.",
    )
    ap.add_argument(
        "--workers",
        type=int,
        default=4,
        metavar="N",
        help="Parallel workers for each stage (default 4). Use 1 for sequential within stage.",
    )
    ap.add_argument(
        "--provider",
        choices=("openai", "anthropic", "gemini"),
        default=(os.environ.get("LLM_PROVIDER") or "openai").strip().lower() or "openai",
        help="LLM for reconcile_reasoning and empty_estimate (sets LLM_PROVIDER; needs matching API key).",
    )
    ap.add_argument(
        "--run1-provider",
        choices=("openai", "anthropic", "gemini"),
        default="openai",
        help="LLM for the first full pipeline pass (reasoning1/).",
    )
    ap.add_argument(
        "--run2-provider",
        choices=("openai", "anthropic", "gemini"),
        default="openai",
        help="LLM for the second full pipeline pass (reasoning2/).",
    )
    ap.add_argument(
        "--submission-dir",
        default=None,
        help="Folder containing pdfs/ and study_definitions.csv (default: directory of this script).",
    )
    args = ap.parse_args()
    workers = max(1, int(args.workers))

    submission_dir = Path(args.submission_dir).resolve() if args.submission_dir else Path(__file__).resolve().parent

    _patch_dataset_paths_for_submission(
        submission_dir=submission_dir,
        provider=str(args.provider),
    )

    print(f"\n=== Stage 1/3: run_study.py (--workers {workers}) ===", flush=True)
    _run_stage(
        "run_study",
        workers,
        extra_args=["--run1-provider", str(args.run1_provider), "--run2-provider", str(args.run2_provider)],
    )

    print(f"\n=== Stage 2/3: reconcile_reasoning.py (--workers {workers}) ===", flush=True)
    _run_stage("reconcile_reasoning", workers)

    print(f"\n=== Stage 3/3: empty_estimate.py (--workers {workers}) ===", flush=True)
    _run_stage("empty_estimate", workers)

    print("\nAll submission steps finished successfully.", flush=True)


if __name__ == "__main__":
    main()

